diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..629dc3329ac1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4524,10 +4524,28 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
   // icmp (X ^ Y_NonZero) s>= X --> icmp (X ^ Y_NonZero) s> X
   // icmp (X ^ Y_NonZero) s<= X --> icmp (X ^ Y_NonZero) s< X
   CmpInst::Predicate PredOut = CmpInst::getStrictPredicate(Pred);
+  if (PredOut != Pred &&
+      isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
   if (PredOut != Pred &&
       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
     return new ICmpInst(PredOut, Op0, Op1);

+  // (~X ^ Y) < ~Z --> (X ^ Y) > Z
+  // (~X ^ Y) > ~Z --> (X ^ Y) < Z
+  // (~X ^ Y) <= ~Z --> (X ^ Y) >= Z
+  // (~X ^ Y) >= ~Z --> (X ^ Y) <= Z
+  // Since (~X ^ Y) = ~(X ^ Y), complement reverses comparison direction.
+  Value *X, *Y, *Z;
+  BinaryOperator *InnerXor;
+  if (match(Op1, m_c_Xor(m_Value(Z), m_AllOnes())) &&
+      match(Op0, m_c_Xor(m_BinOp(InnerXor), m_Value(Y))) &&
+      InnerXor->getOpcode() == Instruction::Xor &&
+      match(InnerXor, m_c_Xor(m_Value(X), m_AllOnes()))) {
+    Value *NewXor = IC.Builder.CreateXor(X, Y);
+    CmpInst::Predicate NewPred = ICmpInst::getSwappedPredicate(Pred);
+    return new ICmpInst(NewPred, NewXor, Z);
+  }
+
   return nullptr;
 }

